import * as THREE from "three";

export interface TextureSetData {
  ao: THREE.Texture;
  color: THREE.Texture;
  displacement: THREE.Texture;
  normal: THREE.Texture;
  roughness: THREE.Texture;
}

export class TextureSet {
  private loadPromise: Promise<TextureSetData> | null = null;

  constructor(private name: string) {}

  load(): Promise<TextureSetData> {
    return this.loadPromise ??= this.loadAll();
  }

  private async loadAll(): Promise<TextureSetData> {
    const loader = new THREE.TextureLoader();
    const basePath = `/textures/${this.name}`;

    const load = (name: string) => new Promise<THREE.Texture>((resolve, reject) => {
      loader.load(`${basePath}/${name}.jpg`, resolve, undefined, reject);
    });

    const [ao, color, displacement, normal, roughness] = await Promise.all([
      load("ao"),
      load("color"),
      load("displacement"),
      load("normal"),
      load("roughness"),
    ]);

    return { ao, color, displacement, normal, roughness };
  }
}
